class Solution:
    def ambiguousCoordinates(self, s):
        digits = s[1:-1]
        n = len(digits)

        def valid_int(d):
            if len(d) == 0:
                return False
            if len(d) > 1 and d[0] == '0':
                return False
            return True

        def options(d):
            out = []
            if valid_int(d):
                out.append(d)
            for k in range(1, len(d)):
                a, b = d[:k], d[k:]
                if len(a) > 1 and a[0] == '0':
                    continue
                if b[-1] == '0':
                    continue
                out.append(a + '.' + b)
            return out

        res = []
        for i in range(1, n):
            for L in options(digits[:i]):
                for R in options(digits[i:]):
                    res.append('(' + L + ', ' + R + ')')
        return res

