class Solution:
    def ambiguousCoordinates(self, s):
        core = s[1:-1]

        def make(d):
            res = []
            m = len(d)
            if m == 1:
                return [d]
            if d[0] == '0':
                if d[-1] != '0':
                    res.append('0.' + d[1:])
                return res
            if d[-1] == '0':
                return [d]
            res.append(d)
            for p in range(1, m):
                res.append(d[:p] + '.' + d[p:])
            return res

        out = []
        for cut in range(1, len(core)):
            left = make(core[:cut])
            right = make(core[cut:])
            for a in left:
                for b in right:
                    out.append('(' + a + ', ' + b + ')')
        return out

