var ambiguousCoordinates = function(s) {
    const core = s.slice(1, -1);
    const make = (d) => {
        const res = [];
        const m = d.length;
        if (m === 1) return [d];
        if (d[0] === '0') {
            if (d[m - 1] !== '0') res.push('0.' + d.slice(1));
            return res;
        }
        if (d[m - 1] === '0') return [d];
        res.push(d);
        for (let p = 1; p < m; p++) res.push(d.slice(0, p) + '.' + d.slice(p));
        return res;
    };
    const out = [];
    for (let cut = 1; cut < core.length; cut++) {
        const left = make(core.slice(0, cut));
        const right = make(core.slice(cut));
        for (const a of left) {
            for (const b of right) {
                out.push('(' + a + ', ' + b + ')');
            }
        }
    }
    return out;
};
